-- Lote 3: Igreja Primitiva, Autoridade, Imagens, Veneração
INSERT INTO ai_knowledge_base (category, topic, core_teaching, bible_references, summary, keywords) VALUES

('Igreja Primitiva', 'Ritos e Liturgia da Igreja Primitiva',
'O culto cristão primitivo não era improvisado, mas um ato sagrado com estrutura herdada dos apóstolos. Elementos fixos: leitura das Escrituras, homilia pelo bispo ou presbítero, orações comunitárias, sinal da paz, ofertório (pão e vinho ao altar), oração eucarística com consagração, e comunhão. São Justino Mártir (ano 155) descreve: reunião no domingo, leitura, exortação, oração, pão e vinho trazidos, ação de graças, e distribuição. A Didachê (90-100) ordena reunir-se no dia do Senhor para partir o pão e dar graças, após confessar os pecados. O culto tinha duas partes: Liturgia da Palavra e Liturgia da Eucaristia — mesma estrutura da Missa atual. Nos primeiros séculos celebravam em casas, depois catacumbas, e após 313 em basílicas.',
ARRAY['At 2:42','At 2:46','1Cor 11:23-26','Ef 5:19','Cl 3:16','1Tm 4:13','At 4:24','1Cor 14:40'],
'O culto primitivo já era estruturado, bíblico e sacramental: leitura, pregação, Eucaristia e oração — mesma estrutura da Missa atual.',
ARRAY['igreja primitiva','liturgia','missa','culto','eucaristia','didachê','justino mártir','tradição apostólica']),

('Igreja Primitiva', 'Batismo Infantil',
'O batismo infantil é bíblico, histórico e apostólico. Na mentalidade hebraica, a aliança sempre incluía a família inteira. A circuncisão era dada a meninos de 8 dias sem exigir entendimento (Gn 17:12). O batismo substitui a circuncisão como sinal da nova aliança (Cl 2:11-12). Pedro declara: "A promessa é para vós e para vossos filhos" (At 2:39). No NT, famílias inteiras são batizadas: Lídia (At 16:15), carcereiro de Filipos (At 16:33), casa de Estéfanas (1Cor 1:16). O termo oikos (casa/família) inclui filhos e dependentes. A fé da comunidade supre a fé da criança (Mc 2:5 — Jesus cura pela fé dos amigos). Orígenes (séc. III) confirma: "A Igreja recebeu dos apóstolos a tradição de batizar crianças." O Concílio de Cartago (418) condenou quem negasse batismo às crianças.',
ARRAY['Cl 2:11-12','At 2:39','At 16:15','At 16:33','1Cor 1:16','Gn 17:12','Mc 2:5','Mc 10:13-16','Hb 8:6'],
'O batismo infantil continua a lógica da aliança bíblica que sempre incluiu famílias inteiras. É prática apostólica confirmada pelos Pais da Igreja.',
ARRAY['batismo infantil','aliança','circuncisão','família','oikos','tradição apostólica','sacramento']),

('Autoridade da Igreja', 'Sucessão Apostólica',
'A sucessão apostólica é a transmissão ininterrupta da autoridade dos apóstolos para os bispos, por imposição das mãos e ordenação sacramental. Jesus deu a Pedro as chaves e poder de ligar/desligar (Mt 16:18-19). Paulo mandou Timóteo transmitir o ensinamento a homens fiéis (2Tm 2:2). A ordenação era por imposição de mãos (At 6:6, 1Tm 4:14). A Igreja distinguiu funções desde o início: bispo (episkopos = supervisor, sucessor dos apóstolos), presbítero (ancião, coopera com o bispo), diácono (servidor). Santo Irineu de Lião (180) já listava a sucessão dos bispos de Roma desde Pedro. Mais de 262 papas sucederam Pedro. Se a missão dada por Cristo era fazer discípulos até o fim dos tempos (Mt 28:20), essa autoridade não pode ter desaparecido.',
ARRAY['Mt 16:18-19','2Tm 2:2','At 6:6','1Tm 4:14','At 15','Mt 28:20'],
'Sucessão apostólica: transmissão ininterrupta de autoridade dos apóstolos aos bispos por imposição de mãos. Garante continuidade da Igreja de Cristo.',
ARRAY['sucessão apostólica','bispos','papado','autoridade','imposição de mãos','pedro','igreja']),

('Autoridade da Igreja', 'Pedro e o Papado',
'Cristo edificou Sua Igreja sobre Pedro como fundamento visível. Em Mt 16:18-19, Jesus dá a Pedro novo nome (indica missão), chaves (autoridade real delegada, cf. Is 22:22) e poder de ligar/desligar (decisões obrigatórias). Após a Ressurreição, confirma Pedro três vezes: "Apascenta minhas ovelhas" (Jo 21:15-17), entregando todo o rebanho. Jesus orou especialmente por Pedro para que sua fé não desfaleça e ele fortaleça os irmãos (Lc 22:31-32). Em Atos, Pedro lidera: escolha de Matias, Pentecostes, primeiro milagre, abertura aos gentios, palavra final no Concílio de Jerusalém. No aramaico, Jesus usou a mesma palavra — Kepha — para Pedro e rocha. Cristo é a rocha eterna, mas quis um líder visível para manter a unidade.',
ARRAY['Mt 16:18-19','Jo 21:15-17','Lc 22:31-32','Is 22:22','At 1:15-26','At 2:14-41','At 10:34-48','At 15:7-11'],
'Pedro recebeu de Cristo as chaves, o mandato pastoral e a liderança visível da Igreja. O papado é continuação dessa missão.',
ARRAY['pedro','papado','chaves','rocha','primado','autoridade','liderança','igreja']),

('Igreja Primitiva', 'Adoração vs Veneração',
'Adoração (latria) é culto exclusivo a Deus: envolve sacrifício, proclamação de divindade e culto litúrgico. Veneração (dulia) é reconhecer valor e respeito — honra a pessoas, santos, líderes. Deus ordena "Honra teu pai e tua mãe" (Ex 20:12) — honra não é idolatria. Na Bíblia, pessoas se prostram diante de outras sem idolatria: Natã diante de Davi (1Rs 1:23), Abigail diante de Davi (1Sm 25:23). O gesto externo não define idolatria — o alvo e a intenção sim. A Igreja sempre distinguiu: latria (adoração) só para Deus, dulia (veneração) para santos, hyperdulia para Maria. Os primeiros cristãos honravam mártires visitando sepulturas e celebrando Eucaristia no aniversário do martírio. O Concílio de Niceia II (787) reafirmou: a honra prestada à imagem passa para o protótipo.',
ARRAY['Mt 4:10','Ex 20:12','1Pe 2:17','1Rs 1:23','1Sm 25:23','Hb 13:7','1Cor 11:1','Ap 4:8-11'],
'Adoração é exclusiva a Deus; veneração é honra legítima a santos e Maria. Gesto externo não define idolatria — o alvo e intenção sim.',
ARRAY['adoração','veneração','latria','dulia','hyperdulia','santos','honra','idolatria']),

('Igreja Primitiva', 'Imagens Sagradas',
'A proibição bíblica não é contra imagens em si, mas contra idolatria. O mesmo Deus que disse "não farás imagem" (Ex 20:4) mandou fazer querubins de ouro para a Arca (Ex 25:18), serpente de bronze para cura (Nm 21:8-9), e o templo repleto de figuras esculpidas (1Rs 6:23-28). A palavra "pesel" (hebraico) refere-se a imagem talhada para culto idolátrico — a chave está em "não as adorarás". Nos séculos I-III, cristãos nas catacumbas usavam símbolos como peixe, âncora e cruz — sinais de fé, não enfeites. Com o Édito de Milão (313), igrejas passaram a usar mosaicos e esculturas para ensinar o povo. A arte sagrada sempre foi usada para glorificar a Deus e instruir os fiéis.',
ARRAY['Ex 20:4-5','Ex 25:18','Nm 21:8-9','1Rs 6:23-28','2Rs 18:4','Ez 41:18-19'],
'Imagens sagradas são bíblicas — Deus mesmo ordenou querubins e serpente de bronze. A proibição é contra adorá-las como deuses, não contra a arte sacra.',
ARRAY['imagens','ídolos','querubins','arte sacra','catacumbas','proibição','adoração']);
